'use strict';

const { dialog, Notification } = require('electron');
const { autoUpdater } = require('electron-updater');

/**
 * Configures the electron-updater autoUpdater instance.
 * - Disables auto-download so the user can accept before downloading.
 * - Suppresses built-in dialogs in favor of custom notifications/dialogs.
 */
function configure() {
  autoUpdater.autoDownload = false;
  autoUpdater.autoInstallOnAppQuit = false;

  autoUpdater.on('update-available', (info) => {
    const version = info.version || 'unknown';

    // Show a system notification with the new version number
    if (Notification.isSupported()) {
      const notification = new Notification({
        title: 'Update Available',
        body: `A new version (v${version}) of Audira Route is available. Click to download.`,
      });

      notification.on('click', () => {
        downloadUpdate();
      });

      notification.show();
    } else {
      // Fallback: use a dialog if notifications are not supported
      dialog
        .showMessageBox({
          type: 'info',
          title: 'Update Available',
          message: `A new version (v${version}) of Audira Route is available.`,
          buttons: ['Download', 'Later'],
          defaultId: 0,
          cancelId: 1,
        })
        .then((result) => {
          if (result.response === 0) {
            downloadUpdate();
          }
        });
    }
  });

  autoUpdater.on('update-downloaded', (info) => {
    const version = info.version || 'unknown';

    dialog
      .showMessageBox({
        type: 'info',
        title: 'Update Ready',
        message: `Version ${version} has been downloaded. Restart now to apply the update?`,
        buttons: ['Restart Now', 'Later'],
        defaultId: 0,
        cancelId: 1,
      })
      .then((result) => {
        if (result.response === 0) {
          quitAndInstall();
        }
      });
  });

  autoUpdater.on('error', (err) => {
    // Silently catch network errors and log to console.
    // The update will be retried on the next application launch.
    console.error('[AutoUpdater] Error checking for updates:', err.message);
  });
}

/**
 * Checks for available updates from the configured update server.
 * Should be called once on app ready. Network errors are silently caught.
 */
function checkForUpdates() {
  autoUpdater.checkForUpdates().catch((err) => {
    // Silently swallow network errors — retry on next launch
    console.error('[AutoUpdater] Failed to check for updates:', err.message);
  });
}

/**
 * Downloads the available update in the background.
 */
function downloadUpdate() {
  autoUpdater.downloadUpdate().catch((err) => {
    console.error('[AutoUpdater] Failed to download update:', err.message);
  });
}

/**
 * Quits the application and installs the downloaded update.
 */
function quitAndInstall() {
  autoUpdater.quitAndInstall();
}

// Run configuration immediately on module load
configure();

module.exports = {
  checkForUpdates,
  downloadUpdate,
  quitAndInstall,
};

'use strict';

const { app, dialog } = require('electron');
const serverManager = require('./src/serverManager');
const windowManager = require('./src/windowManager');
const trayManager = require('./src/trayManager');
const { ensureDataDir } = require('./src/utils/dataDir');

/**
 * Flag indicating the application is in the process of quitting.
 * When true, the window close event will not be intercepted (close-to-tray disabled).
 * @type {boolean}
 */
let isQuitting = false;

/**
 * Gracefully shuts down the application:
 * 1. Sets isQuitting flag to prevent close-to-tray interception
 * 2. Stops the embedded server
 * 3. Destroys the tray icon
 * 4. Exits the application
 */
async function gracefulShutdown() {
  if (isQuitting) {
    return;
  }

  isQuitting = true;

  try {
    await serverManager.stop();
  } catch {
    // Best-effort shutdown — continue even if server stop fails
  }

  trayManager.destroy();
  app.exit(0);
}

/**
 * Displays an error dialog when the server fails to start.
 * Offers the user a choice to retry starting the server or quit the application.
 *
 * @param {Error} err - The error that caused the server start failure
 */
async function showServerErrorDialog(err) {
  const result = await dialog.showMessageBox({
    type: 'error',
    title: 'Server Start Failed',
    message: 'Audira Route server failed to start.',
    detail: err.message || 'Unknown error occurred.',
    buttons: ['Retry', 'Quit'],
    defaultId: 0,
    cancelId: 1,
  });

  if (result.response === 0) {
    // Retry
    await startServer();
  } else {
    // Quit
    app.exit(1);
  }
}

/**
 * Starts the embedded server and creates the window once ready.
 * If the server fails to start, shows an error dialog with retry/quit options.
 */
async function startServer() {
  try {
    ensureDataDir();
    await serverManager.start();
    const win = windowManager.createWindow();
    setupCloseToTray(win);
  } catch (err) {
    await showServerErrorDialog(err);
  }
}

/**
 * Sets up close-to-tray behavior on the window.
 * When the user closes the window, it is hidden instead of destroyed,
 * unless the isQuitting flag is set (indicating a real quit).
 *
 * @param {Electron.BrowserWindow} win
 */
function setupCloseToTray(win) {
  win.on('close', (event) => {
    if (!isQuitting) {
      event.preventDefault();
      windowManager.hide();
    }
  });
}

/**
 * Main application startup sequence.
 * Requests single-instance lock, starts server, creates window, tray, and checks for updates.
 */
function main() {
  // Single-instance lock: only one instance of the app should run at a time
  const gotLock = app.requestSingleInstanceLock();

  if (!gotLock) {
    // Another instance is already running — exit immediately
    app.quit();
    return;
  }

  // When a second instance is launched, focus the existing window
  app.on('second-instance', () => {
    windowManager.show();
    windowManager.focus();
  });

  // Handle OS shutdown / user-initiated quit
  app.on('before-quit', (event) => {
    event.preventDefault();
    gracefulShutdown();
  });

  app.whenReady().then(async () => {
    // Start the server and create the window
    await startServer();

    // Create system tray icon and menu
    trayManager.create();

    // Check for updates (auto-updater may not be implemented yet)
    try {
      const autoUpdater = require('./src/autoUpdater');
      if (autoUpdater && typeof autoUpdater.checkForUpdates === 'function') {
        autoUpdater.checkForUpdates();
      }
    } catch {
      // Auto-updater module not available yet — skip silently
    }
  });
}

main();

